  ('social-worker-moex-04051', 'social-worker', 'social-worker-moex-111-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作的專業價值與社會環境具有密不可分的關係，足以影響社會工作價值脈絡之因素相 當多。下列敘述何者錯誤？', '["當前的社會與文化價值，提供社會工作者和案主合作時對案主所處環境脈絡之瞭解", "社會福利機構的宗旨、目標、服務流程和責信，皆可能反映了機構的價值取向", "社會工作所服務的案主以弱勢族群居多。因此，案主系統的價值觀變異不大", "社會工作者應該時時檢視自己的價值觀，及個人價值觀對服務輸送的可能影響"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "05188af2adcc", "answer_pdf_sha1": "aea6905a7961", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
